function renderVerkosto(t,o,e){const r=t.verkosto[o];if(!r)return;const s=t.entities;let n=`\n        <div class="verkosto-header" style="text-align: center; margin-bottom: 2rem;">\n            <h2 style="color: #0a2540; margin-bottom: 0.5rem;">🧠 Palveluverkoston suositukset: ${r.otsikko}</h2>\n            <p style="color: #4a5568;">Saattaisit olla kiinnostunut myös näistä paikallisista toimijoista ja mahdollisuuksista.</p>\n        </div>\n        <div class="verkosto-grid" style="display: grid; grid-template-columns: repeat(auto-fit, minmax(250px, 1fr)); gap: 1.5rem;">\n    `;r.yritykset.length>0&&(n+='<div class="verkosto-kategoria" style="background: white; padding: 1.5rem; border-radius: 12px; box-shadow: 0 4px 15px rgba(0,0,0,0.05);">\n            <h3 style="color: #0056b3; margin-bottom: 1rem; font-size: 1.2rem;">🏢 Yritykset</h3>\n            <ul style="list-style: none; padding: 0; margin: 0;">',r.yritykset.forEach(t=>{const o=s[t];o&&(n+=`<li style="margin-bottom: 0.5rem; border-bottom: 1px solid #eee; padding-bottom: 0.5rem;"><strong>${o.nimi}</strong><br><small style="color: #666;">${o.kuvaus}</small></li>`)}),n+="</ul></div>"),r.tarjoan_apua.length>0&&(n+='<div class="verkosto-kategoria" style="background: white; padding: 1.5rem; border-radius: 12px; box-shadow: 0 4px 15px rgba(0,0,0,0.05);">\n            <h3 style="color: #28a745; margin-bottom: 1rem; font-size: 1.2rem;">🤝 Tarjoaa apua</h3>\n            <ul style="list-style: none; padding: 0; margin: 0;">',r.tarjoan_apua.forEach(t=>{const o=s[t];o&&(n+=`<li style="margin-bottom: 0.5rem; border-bottom: 1px solid #eee; padding-bottom: 0.5rem;"><strong>${o.otsikko}</strong></li>`)}),n+="</ul></div>"),r.harrastukset.length>0&&(n+='<div class="verkosto-kategoria" style="background: white; padding: 1.5rem; border-radius: 12px; box-shadow: 0 4px 15px rgba(0,0,0,0.05);">\n            <h3 style="color: #ffc107; margin-bottom: 1rem; font-size: 1.2rem;">👥 Harrastusryhmät</h3>\n            <ul style="list-style: none; padding: 0; margin: 0;">',r.harrastukset.forEach(t=>{const o=s[t];o&&(n+=`<li style="margin-bottom: 0.5rem; border-bottom: 1px solid #eee; padding-bottom: 0.5rem;"><strong>${o.otsikko}</strong><br><small style="color: #666;">Kiinnostuneita: ${o.kiinnostuneet}</small></li>`)}),n+="</ul></div>"),r.projektit.length>0&&(n+='<div class="verkosto-kategoria" style="background: white; padding: 1.5rem; border-radius: 12px; box-shadow: 0 4px 15px rgba(0,0,0,0.05);">\n            <h3 style="color: #dc3545; margin-bottom: 1rem; font-size: 1.2rem;">🚀 Projektit</h3>\n            <ul style="list-style: none; padding: 0; margin: 0;">',r.projektit.forEach(t=>{const o=s[t];o&&(n+=`<li style="margin-bottom: 0.5rem; border-bottom: 1px solid #eee; padding-bottom: 0.5rem;"><strong>${o.otsikko}</strong></li>`)}),n+="</ul></div>"),n+="</div>",n+='<div style="text-align: center; margin-top: 2rem;">\n        <p style="color: #666; font-size: 0.9rem; margin-bottom: 0.5rem;">Kokeile muita suositusteemoja:</p>\n        <div style="display: flex; justify-content: center; gap: 0.5rem; flex-wrap: wrap;">',Object.keys(t.verkosto).forEach(e=>{n+=`<button onclick="renderVerkostoData('${e}')" style="background: ${e===o?"#0056b3":"#e2e8f0"}; color: ${e===o?"white":"#333"}; border: none; padding: 0.5rem 1rem; border-radius: 20px; cursor: pointer; font-family: inherit;">${t.verkosto[e].otsikko}</button>`}),n+="</div></div>",e.innerHTML=n}document.addEventListener("DOMContentLoaded",()=>{const t=document.getElementById("palveluverkosto-suositukset");t&&fetch("verkosto.json").then(t=>t.json()).then(o=>{const e=Object.keys(o.verkosto);renderVerkosto(o,e[Math.floor(Math.random()*e.length)],t)}).catch(t=>console.error("Virhe ladattaessa verkosto.json:",t))}),window.renderVerkostoData=function(t){fetch("verkosto.json").then(t=>t.json()).then(o=>{const e=document.getElementById("palveluverkosto-suositukset");renderVerkosto(o,t,e)})};